#include <stdio.h>
#include <string.h>
#include <time.h>
#include <sha2.h>

typedef struct {
 int height;
 char previousHash[65];
 time_t timestamp;
 char message[256];
 int coinbaseReward;
} GenesisBlock;

void createGenesisBlock(GenesisBlock* block, time_t timestamp, const char* message) {
 block->height = 0;
 strcpy(block->previousHash, "0");
 block->timestamp = timestamp;
 strcpy(block->message, message);
 block->coinbaseReward = 50; // unspendable
}

void calculateHash(GenesisBlock* block, char* hash) {
 char data[256];
 sprintf(data, "%d%s%ld%s", block->height, block->previousHash, block->timestamp, block->message);
 SHA256_CTX ctx;
 SHA256_Init(&ctx);
 SHA256_Update(&ctx, data, strlen(data));
 SHA256_Final(hash, &ctx);
}

int main() {
 GenesisBlock block;
 time_t timestamp = time(NULL);
 const char* message = "The Times 03/Jan/2009 Chancellor on brink of second bailout for banks";
 createGenesisBlock(&block, timestamp, message);
 char hash[65];
 calculateHash(&block, hash);
 printf("%s\n", hash);
 return 0;
}
